['yunet] [--nima]\n\nIf no arguments provided, downloads both models.\n"', '\n\nimport argparse\nimport urllib.request\nimport sys\nfrom pathlib import Path\n\n# YuNet model URL from OpenCV Zoo\nYUNET_URL = "https://github.com/opencv/opencv_zoo/raw/main/models/face_detection_yunet/face_detection_yunet_2023mar.onnx"\nYUNET_PATH = Path("models/face_detection_yunet_2023mar.onnx")\n\ndef download_yunet():\n    "', 'Download YuNet face detection model."', '\n    print("Downloading YuNet face detection model...', 'try:\n        # Create models directory if it doesn\'t exist\n        YUNET_PATH.parent.mkdir(parents=True, exist_ok=True)\n        \n        # Download the model\n        urllib.request.urlretrieve(YUNET_URL, str(YUNET_PATH))\n        print(f"YuNet model downloaded successfully to {YUNET_PATH}")\n        return True\n    except Exception as e:\n        print(f"Failed to download YuNet model: {e}")\n        return False\n\ndef run_nima_setup():\n    "', 'Run NIMA setup script to generate aesthetic assessment model."', '\n    print("Setting up NIMA neural image assessment model...")\n    try:\n        # Import and run the NIMA setup\n        import nima_setup\n        success = nima_setup.build_nima_onnx()\n        if success:\n            print("NIMA model setup completed successfully")\n            return True\n        else:\n            print("NIMA model setup failed")\n            return False\n    except Exception as e:\n        print(f"Failed to run NIMA setup: {e}")\n        return False\n\ndef main():\n    parser = argparse.ArgumentParser(description="Integrate optional models for enhanced grading")\n    parser.add_argument("--yunet', 'action="store_true', 'help="Download YuNet face detection model")\n    parser.add_argument("--nima', 'action="store_true', 'help="Setup NIMA neural image assessment model', 'args = parser.parse_args()\n    \n    # If no arguments provided, do both\n    if not args.yunet and not args.nima:\n        args.yunet = True\n        args.nima = True\n    \n    success = True\n    \n    if args.yunet:\n        if not download_yunet():\n            success = False\n    \n    if args.nima:\n        if not run_nima_setup():\n            success = False\n    \n    if success:\n        print("\nModel integration completed!")\n        if args.yunet:\n            print("- YuNet face detection model is ready")\n        if args.nima:\n            print("- NIMA neural image assessment model is ready")\n        print("\nRestart the application to use the new models.")\n    else:\n        print("\nSome model integrations failed. Check the errors above.")\n        sys.exit(1)\n\nif __name__ == "__main__', 'main()']